custom_css:
@import url('https://fonts.googleapis.com/css2?family=Comfortaa:wght@500;700&family=Exo+2:wght@400;500;700&family=Tektur:wght@400;600;700&display=swap');
body { font-family: 'Comfortaa', cursive !important; background-color: #161a17 !important; }
.fa, .fas, .fa-solid, .recentChatInfo .fa, .recentChatInfo .fas, .recentChatInfo .fa-solid, .menu_button[class*="fa-"] { font-family: 'Font Awesome 6 Free' !important; font-weight: 900 !important; }
.far, .fa-regular, .recentChatInfo .far, .recentChatInfo .fa-regular { font-family: 'Font Awesome 6 Free' !important; font-weight: 400 !important; }
.fab, .fa-brands, .recentChatInfo .fab, .recentChatInfo .fa-brands { font-family: 'Font Awesome 6 Brands' !important; font-weight: 400 !important; }
.mes { background: #1e241f !important; border: 2px solid #9ab29d !important; border-radius: 20px !important; box-shadow: 4px 4px 0px #c1dfc4 !important; margin-bottom: 24px !important; padding: 18px !important; }
.mes_text { font-family: 'Exo 2', sans-serif !important; font-size: 0.95em !important; }
.ch_name, .name_text, .chat_name, .characterName { font-family: 'Tektur', sans-serif !important; color: #c1dfc4 !important; font-size: 1em !important; font-weight: 700 !important; }
.avatar img { border-radius: 50% !important; border: 2px solid #9ab29d !important; box-shadow: 3px 3px 0px #c1dfc4 !important; width: 50px !important; height: 50px !important; }
.menu_button, .menu_button i, .menu_button svg { color: #c1dfc4 !important; fill: #c1dfc4 !important; opacity: 1 !important; stroke: none !important; }
.drawer-icon, .drawer-icon i, .drawer-icon svg, #rm_button_group .menu_button, #rm_button_group i, #rm_button_group svg, #rm_button_group path { color: #9ab29d !important; fill: #9ab29d !important; opacity: 1 !important; stroke: none !important; text-shadow: none !important; }
.recentChatInfo .chatNameContainer, .recentChatInfo .chatNameContainer span, .recentChatInfo .chatNameContainer div { font-family: 'Tektur', sans-serif !important; color: #c1dfc4 !important; font-weight: bold !important; opacity: 1 !important; }
#options_button i::before, .fa-bars::before { content: '' !important; display: inline-block !important; width: 18px !important; height: 18px !important; background-color: #c1dfc4 !important; -webkit-mask-image: url('https://img.icons8.ru/ios-filled/50/do-not-disturb-2.png') !important; mask-image: url('https://img.icons8.ru/ios-filled/50/do-not-disturb-2.png') !important; -webkit-mask-size: contain !important; mask-size: contain !important; -webkit-mask-position: center !important; mask-position: center !important; -webkit-mask-repeat: no-repeat !important; mask-repeat: no-repeat !important; }
#extensionsMenuButton::before, #extensionsMenuButton i::before, #chat_wand_button i::before, #slash_button i::before, #qr_button i::before, #slash_commands_button i::before, .fa-wand-magic-sparkles::before, .fa-wand-magic::before, .fa-magic::before { content: '' !important; display: inline-block !important; width: 18px !important; height: 18px !important; background-color: #c1dfc4 !important; -webkit-mask-image: url('https://img.icons8.ru/ios-filled/50/sparkling--v1.png') !important; mask-image: url('https://img.icons8.ru/ios-filled/50/sparkling--v1.png') !important; -webkit-mask-size: contain !important; mask-size: contain !important; -webkit-mask-position: center !important; mask-position: center !important; -webkit-mask-repeat: no-repeat !important; mask-repeat: no-repeat !important; }
#send_but i::before, .fa-paper-plane::before { content: '\f04b' !important; font-family: 'Font Awesome 6 Free' !important; font-weight: 900 !important; color: #c1dfc4 !important; font-size: 1.1em; text-shadow: 0 0 8px rgba(141, 183, 213, 0.6) !important; }
#send_form { background: #1e241f !important; border: 2px solid #9ab29d !important; border-radius: 20px !important; margin: 4px 0 !important; padding: 4px !important; box-sizing: border-box !important; }
#send_textarea { background: transparent !important; border: none !important; color: #f0f0fa !important; padding: 4px 8px !important; font-family: 'Exo 2', sans-serif !important; font-size: 14px !important; resize: none !important; outline: none !important; box-shadow: none !important; }
#leftSendForm, #rightSendForm { gap: 2px !important; padding: 0 !important; }
#options_button, #chat_wand_button, #extensionsMenuButton, #send_but { padding: 8px !important; margin: 0 !important; }
